public class Solution {
    private Map<Integer, Long> memo = new HashMap<>();

    public long fib(int n) {
        if (n <= 1) return n;              // base cases
        if (memo.containsKey(n)) return memo.get(n);  // cached
        long result = fib(n - 1) + fib(n - 2);        // recurse
        memo.put(n, result);               // cache the answer
        return result;
    }

    // Bottom-up equivalent (O(1) space):
    public long fibBottomUp(int n) {
        if (n <= 1) return n;
        long prev2 = 0, prev1 = 1;
        for (int i = 2; i <= n; i++) {
            long curr = prev1 + prev2;
            prev2 = prev1;
            prev1 = curr;
        }
        return prev1;
    }
}

public class Solution {
    public int coinChange(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1);  // sentinel: 'impossible'
        dp[0] = 0;                    // 0 coins for amount 0

        for (int a = 1; a <= amount; a++) {
            for (int coin : coins) {
                if (coin <= a) {
                    dp[a] = Math.min(dp[a], dp[a - coin] + 1);
                }
            }
        }

        return dp[amount] > amount ? -1 : dp[amount];
    }
}

public class Solution {
    public int knapsack(int[] weights, int[] values, int capacity) {
        int n = weights.length;
        // dp[i][w] = max value using first i items with capacity w
        int[][] dp = new int[n + 1][capacity + 1];

        for (int i = 1; i <= n; i++) {
            for (int w = 0; w <= capacity; w++) {
                dp[i][w] = dp[i-1][w];  // skip item i
                if (weights[i-1] <= w) {
                    dp[i][w] = Math.max(dp[i][w],
                        values[i-1] + dp[i-1][w - weights[i-1]]);
                }
            }
        }
        return dp[n][capacity];
    }
}

public class Solution {
    public int longestCommonSubsequence(String text1, String text2) {
        int m = text1.length(), n = text2.length();
        // dp[i][j] = LCS of text1[0..i-1] and text2[0..j-1]
        int[][] dp = new int[m + 1][n + 1];

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (text1.charAt(i-1) == text2.charAt(j-1)) {
                    dp[i][j] = 1 + dp[i-1][j-1];  // chars match: extend
                } else {
                    dp[i][j] = Math.max(dp[i-1][j], dp[i][j-1]);  // skip one
                }
            }
        }
        return dp[m][n];
    }
}

public class Solution {
    // O(n^2) DP solution
    public int lisDP(int[] nums) {
        int n = nums.length;
        int[] dp = new int[n];  // dp[i] = LIS ending at index i
        Arrays.fill(dp, 1);     // each element is LIS of length 1 alone
        int maxLen = 1;
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[j] < nums[i])
                    dp[i] = Math.max(dp[i], dp[j] + 1);
            }
            maxLen = Math.max(maxLen, dp[i]);
        }
        return maxLen;
    }

    // O(n log n) with patience sorting (binary search)
    public int lisOptimal(int[] nums) {
        List<Integer> tails = new ArrayList<>();
        for (int num : nums) {
            int pos = Collections.binarySearch(tails, num);
            if (pos < 0) pos = -(pos + 1);
            if (pos == tails.size()) tails.add(num);
            else tails.set(pos, num);
        }
        return tails.size();
    }
}

